+                        sp.start.line,
+                        sp.start.column + rem,
+                        sp.end.line,
+                        sp.end.column,
+                    )
+                        .into(),
+                    x - rem,
+                ));
+                return sp.start.column + rem - 1;
+            }
+        }
+        unreachable!();
